/** Map a slug back to its city record (O(1) lookup). */
export const CITIES_BY_SLUG: Record<string, QuebecCity> = Object.fromEntries(
  QUEBEC_CITIES.map((c) => [c.slug, c])
);

/** Cities grouped by region slug. */
export function citiesByRegion(regionSlug: string): QuebecCity[] {
  return QUEBEC_CITIES.filter((c) => c.regionSlug === regionSlug);
}

/** Top N cities by population (default 50). */
export function topCities(n = 50): QuebecCity[] {
  return [...QUEBEC_CITIES].sort((a, b) => b.population - a.population).slice(0, n);
}
